import React from 'react';

const Box = ({ active, boxText, onClick, children }) => (
  <div className={`box ${active ? 'active' : ''}`} onClick={onClick}>
    <div className="box-content">
      <h3>{boxText}</h3>
      {!active && <p>{children}</p>}
    </div>
  </div>
);

export default Box;
